import React, { useState, useEffect } from 'react';
import axios from 'axios';
import toast from 'react-hot-toast';

const AdminDashboard = () => {
    const [projects, setProjects] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchAllProjects();
    }, []);

    const fetchAllProjects = async () => {
        try {
            const response = await axios.get('http://localhost:5000/api/admin/all-projects');
            if (response.data.success) {
                setProjects(response.data.data);
            }
        } catch (error) {
            toast.error('Failed to fetch projects');
        } finally {
            setLoading(false);
        }
    };

    const getWinners = async (grade) => {
        try {
            const response = await axios.get(`http://localhost:5000/api/admin/winners/${grade}`);
            if (response.data.success) {
                toast.success(`Winners for Grade ${grade}: ${response.data.winners.map(w => w.team_name).join(', ')}`);
            }
        } catch (error) {
            toast.error('Failed to get winners');
        }
    };

    if (loading) {
        return <div className="text-center py-10">Loading...</div>;
    }

    return (
        <div className="max-w-6xl mx-auto p-6">
            <h2 className="text-2xl font-bold mb-6">📊 Admin Dashboard</h2>
            
            <div className="bg-white rounded-lg shadow-lg overflow-hidden">
                <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                        <tr>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Team</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Grade</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Students</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                        {projects.map((project) => (
                            <tr key={project.id}>
                                <td className="px-6 py-4">
                                    <div className="font-medium">{project.team_name}</div>
                                    <div className="text-sm text-gray-500">{project.project_title}</div>
                                </td>
                                <td className="px-6 py-4">{project.grade} - {project.division}</td>
                                <td className="px-6 py-4">
                                    {JSON.parse(project.students_data || '[]').map(s => s.name).join(', ')}
                                </td>
                                <td className="px-6 py-4">
                                    <span className={`px-2 py-1 rounded-full text-xs ${
                                        project.project_submitted ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'
                                    }`}>
                                        {project.project_submitted ? '✅ Submitted' : '⏳ Pending'}
                                    </span>
                                </td>
                                <td className="px-6 py-4">
                                    <button
                                        onClick={() => getWinners(project.grade)}
                                        className="text-blue-600 hover:text-blue-900 text-sm"
                                    >
                                        Get Winners
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default AdminDashboard;
